#!/usr/bin/env node
/**
 * Link Logger Agent - Production Database System
 * Strategic Link Intelligence Management
 *
 * @author link-logger-agent
 * @version 1.0.0
 * @created 2025-10-31
 */

const fs = require('fs').promises;
const path = require('path');
const crypto = require('crypto');

class LinkDatabase {
  constructor(basePath = '/workspaces/agent-feed/prod/agent_workspace/link-logger-agent') {
    this.basePath = basePath;
    this.databasePath = path.join(basePath, 'database');
    this.schema = null;

    // Initialize database paths
    this.paths = {
      links: path.join(this.databasePath, 'links.json'),
      knowledgeIndex: path.join(this.databasePath, 'knowledge-index.json'),
      searchIndex: path.join(this.databasePath, 'search-index.json'),
      processingQueue: path.join(this.databasePath, 'processing-queue.json'),
      strategicBriefs: path.join(this.databasePath, 'strategic-briefs.json'),
      metadata: path.join(this.databasePath, 'database-metadata.json')
    };
  }

  /**
   * Initialize database system
   */
  async initialize() {
    try {
      // Create directory structure
      await this.ensureDirectories();

      // Load schema
      await this.loadSchema();

      // Initialize empty collections if they don't exist
      await this.initializeCollections();

      console.log('[LinkDB] Database system initialized successfully');
      return true;
    } catch (error) {
      console.error('[LinkDB] Database initialization failed:', error);
      throw error;
    }
  }

  /**
   * Create required directory structure
   */
  async ensureDirectories() {
    const directories = [
      this.databasePath,
      path.join(this.basePath, 'archives'),
      path.join(this.basePath, 'knowledge-base'),
      path.join(this.basePath, 'strategic-intel'),
      path.join(this.basePath, 'competitive-analysis'),
      path.join(this.basePath, 'processed_links'),
      path.join(this.basePath, 'temp')
    ];

    for (const dir of directories) {
      try {
        await fs.access(dir);
      } catch {
        await fs.mkdir(dir, { recursive: true });
        console.log(`[LinkDB] Created directory: ${dir}`);
      }
    }
  }

  /**
   * Load database schema
   */
  async loadSchema() {
    try {
      const schemaPath = path.join(this.basePath, 'database-schema.json');
      const schemaData = await fs.readFile(schemaPath, 'utf8');
      this.schema = JSON.parse(schemaData);
      console.log('[LinkDB] Schema loaded successfully');
    } catch (error) {
      console.error('[LinkDB] Failed to load schema:', error);
      throw error;
    }
  }

  /**
   * Initialize empty collections
   */
  async initializeCollections() {
    const collections = {
      links: [],
      knowledgeIndex: {
        knowledge_entries: [],
        search_index: {},
        strategic_priorities: [],
        last_updated: new Date().toISOString(),
        intelligence_confidence: "MEDIUM",
        source_credibility: "PENDING"
      },
      searchIndex: {},
      processingQueue: [],
      strategicBriefs: [],
      metadata: {
        database_version: this.schema.schema_version,
        created_date: new Date().toISOString(),
        last_updated: new Date().toISOString(),
        total_links: 0,
        total_strategic_intel: 0,
        performance_metrics: {
          avg_processing_time: 0,
          success_rate: 0,
          strategic_hit_rate: 0
        }
      }
    };

    for (const [collectionName, defaultData] of Object.entries(collections)) {
      const filePath = this.paths[collectionName];
      try {
        await fs.access(filePath);
        console.log(`[LinkDB] Collection ${collectionName} exists`);
      } catch {
        await fs.writeFile(filePath, JSON.stringify(defaultData, null, 2));
        console.log(`[LinkDB] Initialized collection: ${collectionName}`);
      }
    }
  }

  /**
   * Generate unique link ID
   */
  generateLinkId() {
    const date = new Date().toISOString().split('T')[0].replace(/-/g, '');
    const uuid = crypto.randomUUID().slice(0, 8);
    return `link-prod-${date}-${uuid}`;
  }

  /**
   * Validate URL format and accessibility
   */
  validateUrl(url) {
    const urlRegex = /^https?:\/\/(www\.)?[-a-zA-Z0-9@:%._\+~#=]{1,256}\.[a-zA-Z0-9()]{1,6}\b([-a-zA-Z0-9()@:%_\+.~#?&//=]*)$/;

    if (!urlRegex.test(url)) {
      throw new Error('Invalid URL format');
    }

    if (url.length > 2048) {
      throw new Error('URL exceeds maximum length');
    }

    // Check blacklist
    const blacklist = this.schema.validation_rules.url_validator.blacklist_domains;
    const domain = new URL(url).hostname;
    if (blacklist.includes(domain)) {
      throw new Error(`Domain ${domain} is blacklisted`);
    }

    return true;
  }

  /**
   * Normalize URL by removing tracking parameters
   */
  normalizeUrl(url) {
    const urlObj = new URL(url);

    // Remove common tracking parameters
    const trackingParams = [
      'utm_source', 'utm_medium', 'utm_campaign', 'utm_content', 'utm_term',
      'fbclid', 'gclid', 'msclkid', 'ref', 'referrer'
    ];

    trackingParams.forEach(param => {
      urlObj.searchParams.delete(param);
    });

    // Normalize protocol to https if http
    if (urlObj.protocol === 'http:') {
      urlObj.protocol = 'https:';
    }

    // Remove trailing slash
    if (urlObj.pathname.endsWith('/') && urlObj.pathname.length > 1) {
      urlObj.pathname = urlObj.pathname.slice(0, -1);
    }

    return urlObj.toString();
  }

  /**
   * Check for duplicate links
   */
  async checkDuplicate(url) {
    const normalizedUrl = this.normalizeUrl(url);
    const links = await this.loadCollection('links');

    // Exact URL match
    const exactMatch = links.find(link => link.url === normalizedUrl);
    if (exactMatch) {
      return { isDuplicate: true, type: 'exact', existingLink: exactMatch };
    }

    // Fuzzy matching by domain + similar path
    const urlObj = new URL(normalizedUrl);
    const domain = urlObj.hostname;
    const pathname = urlObj.pathname;

    const fuzzyMatches = links.filter(link => {
      const existingUrl = new URL(link.url);
      return existingUrl.hostname === domain &&
             this.calculateSimilarity(pathname, existingUrl.pathname) > 0.8;
    });

    if (fuzzyMatches.length > 0) {
      return { isDuplicate: true, type: 'fuzzy', existingLinks: fuzzyMatches };
    }

    return { isDuplicate: false };
  }

  /**
   * Calculate string similarity
   */
  calculateSimilarity(str1, str2) {
    const longer = str1.length > str2.length ? str1 : str2;
    const shorter = str1.length > str2.length ? str2 : str1;

    if (longer.length === 0) return 1.0;

    const distance = this.levenshteinDistance(longer, shorter);
    return (longer.length - distance) / longer.length;
  }

  /**
   * Calculate Levenshtein distance
   */
  levenshteinDistance(str1, str2) {
    const matrix = [];

    for (let i = 0; i <= str2.length; i++) {
      matrix[i] = [i];
    }

    for (let j = 0; j <= str1.length; j++) {
      matrix[0][j] = j;
    }

    for (let i = 1; i <= str2.length; i++) {
      for (let j = 1; j <= str1.length; j++) {
        if (str2.charAt(i - 1) === str1.charAt(j - 1)) {
          matrix[i][j] = matrix[i - 1][j - 1];
        } else {
          matrix[i][j] = Math.min(
            matrix[i - 1][j - 1] + 1,
            matrix[i][j - 1] + 1,
            matrix[i - 1][j] + 1
          );
        }
      }
    }

    return matrix[str2.length][str1.length];
  }

  /**
   * Calculate strategic value score
   */
  calculateStrategicValue(analysis) {
    const weights = {
      business_impact: 0.3,
      competitive_relevance: 0.25,
      market_intelligence_value: 0.25,
      time_sensitivity: 0.2
    };

    let score = 0;
    for (const [metric, weight] of Object.entries(weights)) {
      score += (analysis[metric] || 0) * weight;
    }

    return Math.round(score * 10) / 10;
  }

  /**
   * Load collection from file
   */
  async loadCollection(collectionName) {
    try {
      const filePath = this.paths[collectionName];
      const data = await fs.readFile(filePath, 'utf8');
      return JSON.parse(data);
    } catch (error) {
      console.error(`[LinkDB] Failed to load collection ${collectionName}:`, error);
      throw error;
    }
  }

  /**
   * Save collection to file
   */
  async saveCollection(collectionName, data) {
    try {
      const filePath = this.paths[collectionName];
      await fs.writeFile(filePath, JSON.stringify(data, null, 2));
      console.log(`[LinkDB] Saved collection: ${collectionName}`);
    } catch (error) {
      console.error(`[LinkDB] Failed to save collection ${collectionName}:`, error);
      throw error;
    }
  }

  /**
   * Add new link to database
   */
  async addLink(linkData) {
    try {
      // Validate URL
      this.validateUrl(linkData.url);

      // Normalize URL
      const normalizedUrl = this.normalizeUrl(linkData.url);

      // Check for duplicates
      const duplicateCheck = await this.checkDuplicate(normalizedUrl);
      if (duplicateCheck.isDuplicate) {
        throw new Error(`Duplicate link detected: ${duplicateCheck.type} match found`);
      }

      // Generate ID and prepare link object
      const linkId = this.generateLinkId();
      const now = new Date().toISOString();

      const link = {
        id: linkId,
        url: normalizedUrl,
        original_url: linkData.url,
        captured_date: now,
        metadata: {
          title: linkData.title || 'Untitled',
          description: linkData.description || '',
          author: linkData.author || '',
          publisher: linkData.publisher || '',
