  async checkDuplicate(url) {
    const normalizedUrl = this.normalizeUrl(url);
    const links = await this.loadCollection('links');

    // Exact URL match
    const exactMatch = links.find(link => link.url === normalizedUrl);
    if (exactMatch) {
      return { isDuplicate: true, type: 'exact', existingLink: exactMatch };
    }

    // Fuzzy matching by domain + similar path
    const urlObj = new URL(normalizedUrl);
    const domain = urlObj.hostname;
    const pathname = urlObj.pathname;

    const fuzzyMatches = links.filter(link => {
      const existingUrl = new URL(link.url);
      return existingUrl.hostname === domain &&
             this.calculateSimilarity(pathname, existingUrl.pathname) > 0.8;
    });

