 */

const { spawn } = require('child_process');
const fs = require('fs').promises;
const path = require('path');

class FirecrawlIntegration {
  constructor(basePath = '/workspaces/agent-feed/prod/agent_workspace/link-logger-agent') {
    this.basePath = basePath;
    this.tempPath = path.join(basePath, 'temp');

    // Firecrawl MCP tool configurations
    this.tools = {
      scrape: 'mcp__firecrawl__firecrawl_scrape',
      map: 'mcp__firecrawl__firecrawl_map',
      search: 'mcp__firecrawl__firecrawl_search'
    };

    // Content extraction patterns
    this.extractionPatterns = {
      title: [
        /<title[^>]*>([^<]+)<\/title>/i,
        /<h1[^>]*>([^<]+)<\/h1>/i,
        /<meta[^>]*property=["\']og:title["\'][^>]*content=["\']([^"']+)["\'][^>]*>/i
      ],
      description: [
        /<meta[^>]*name=["\']description["\'][^>]*content=["\']([^"']+)["\'][^>]*>/i,
        /<meta[^>]*property=["\']og:description["\'][^>]*content=["\']([^"']+)["\'][^>]*>/i
      ],
      author: [
        /<meta[^>]*name=["\']author["\'][^>]*content=["\']([^"']+)["\'][^>]*>/i,
        /<meta[^>]*property=["\']article:author["\'][^>]*content=["\']([^"']+)["\'][^>]*>/i
      ],
      publishDate: [
        /<meta[^>]*property=["\']article:published_time["\'][^>]*content=["\']([^"']+)["\'][^>]*>/i,
        /<time[^>]*datetime=["\']([^"']+)["\'][^>]*>/i
      ]
    };

    // Strategic content indicators
    this.strategicIndicators = {
      competitive: [
        'competitor', 'competition', 'market share', 'rival', 'competing',
        'versus', 'vs', 'comparison', 'alternative', 'threat'
      ],
      market: [
        'market', 'industry', 'trend', 'forecast', 'growth', 'analysis',
        'report', 'research', 'survey', 'study', 'projection'
      ],
      technology: [
        'AI', 'artificial intelligence', 'machine learning', 'automation',
        'innovation', 'breakthrough', 'technology', 'platform', 'API'
      ],
      business: [
        'revenue', 'profit', 'investment', 'funding', 'acquisition',
        'partnership', 'strategy', 'business model', 'monetization'
      ]
    };
  }

  /**
   * Initialize Firecrawl integration
   */
  async initialize() {
    try {
      // Ensure temp directory exists
      await fs.mkdir(this.tempPath, { recursive: true });

      console.log('[Firecrawl] Integration initialized');
      return true;
    } catch (error) {
      console.error('[Firecrawl] Initialization failed:', error);
      throw error;
    }
  }

  /**
   * Execute MCP tool command
   */
  async executeMCPCommand(tool, parameters) {
    return new Promise((resolve, reject) => {
      console.log(`[Firecrawl] Executing ${tool} with parameters:`, parameters);

      // For testing purposes, simulate MCP call
      // In production, this would make actual MCP calls
      const mockResponse = this.generateMockResponse(tool, parameters);

      setTimeout(() => {
        resolve(mockResponse);
      }, 1000);
    });
  }

  /**
   * Generate mock response for testing (replace with actual MCP calls)
   */
  generateMockResponse(tool, parameters) {
    const url = parameters.url;
    const domain = new URL(url).hostname;

    switch (tool) {
      case 'mcp__firecrawl__firecrawl_scrape':
        return {
          success: true,
          data: {
            url: url,
            markdown: `# Strategic Content from ${domain}\n\nThis is strategic content that would be extracted from ${url}.\n\n## Key Points\n- Important insight 1\n- Strategic information 2\n- Competitive intelligence 3\n\n## Analysis\nThis content provides valuable strategic intelligence for business decision making.`,
            html: `<html><head><title>Strategic Content</title></head><body><h1>Strategic Content from ${domain}</h1><p>Strategic analysis content...</p></body></html>`,
            rawHtml: `<html><head><title>Strategic Content</title></head><body><h1>Strategic Content from ${domain}</h1><p>Strategic analysis content...</p></body></html>`,
            metadata: {
              title: `Strategic Content from ${domain}`,
              description: 'Strategic business intelligence and market analysis',
              language: 'en',
              sourceURL: url,
              statusCode: 200
            }
          }
        };

      case 'mcp__firecrawl__firecrawl_map':
        return {
          success: true,
          data: {
            links: [
              { url: `${url}/page1`, title: 'Related Strategic Page 1' },
              { url: `${url}/page2`, title: 'Related Strategic Page 2' },
              { url: `${url}/analysis`, title: 'Market Analysis' }
            ]
          }
        };

      case 'mcp__firecrawl__firecrawl_search':
        return {
          success: true,
          data: {
            results: [
              {
                url: `${url}/search1`,
                title: 'Search Result 1',
                description: 'Strategic content related to search'
              }
            ]
          }
        };

      default:
        return { success: false, error: 'Unknown tool' };
    }
  }

  /**
   * Extract content from URL using Firecrawl
   */
  async extractContent(url, options = {}) {
    try {
      console.log(`[Firecrawl] Starting content extraction for: ${url}`);

      // Step 1: Scrape the main content
      const scrapeResult = await this.executeMCPCommand(this.tools.scrape, {
        url: url,
        formats: ['markdown', 'html', 'rawHtml'],
        onlyMainContent: true,
        includeTags: ['title', 'meta', 'h1', 'h2', 'h3', 'p', 'article'],
        excludeTags: ['nav', 'footer', 'aside', 'script', 'style'],
        waitFor: 2000,
        timeout: 30000
      });

      if (!scrapeResult.success) {
        throw new Error(`Scraping failed: ${scrapeResult.error}`);
      }

      const scrapedData = scrapeResult.data;

      // Step 2: Extract and structure metadata
      const extractedContent = {
        url: url,
        raw_content: {
          markdown: scrapedData.markdown || '',
          html: scrapedData.html || '',
          raw_html: scrapedData.rawHtml || ''
        },
        metadata: {
          title: this.extractMetadata('title', scrapedData.rawHtml) || scrapedData.metadata?.title || 'Untitled',
          description: this.extractMetadata('description', scrapedData.rawHtml) || scrapedData.metadata?.description || '',
          author: this.extractMetadata('author', scrapedData.rawHtml) || '',
          publisher: new URL(url).hostname,
          publish_date: this.extractMetadata('publishDate', scrapedData.rawHtml) || '',
          domain: new URL(url).hostname,
          language: scrapedData.metadata?.language || 'en',
          status_code: scrapedData.metadata?.statusCode || 200
        },
        content_analysis: {
          word_count: this.countWords(scrapedData.markdown),
          estimated_read_time: this.estimateReadingTime(scrapedData.markdown),
          content_type: this.determineContentType(scrapedData.markdown, scrapedData.metadata?.title),
          strategic_indicators: this.analyzeStrategicContent(scrapedData.markdown)
        },
        extraction_metadata: {
          extracted_at: new Date().toISOString(),
          extraction_method: 'firecrawl_mcp',
          success: true,
          processing_time: Date.now()
        }
      };

      // Step 3: Optionally map related links
      if (options.includeRelatedLinks) {
        const mapResult = await this.executeMCPCommand(this.tools.map, {
          url: url,
          search: 'analysis, strategic, competitive, market',
          limit: 10
        });

        if (mapResult.success) {
          extractedContent.related_links = mapResult.data.links || [];
        }
      }

      console.log(`[Firecrawl] Content extraction completed for: ${url}`);
      return extractedContent;

    } catch (error) {
      console.error(`[Firecrawl] Content extraction failed for ${url}:`, error);

      return {
        url: url,
        extraction_metadata: {
          extracted_at: new Date().toISOString(),
          extraction_method: 'firecrawl_mcp',
          success: false,
          error: error.message,
          processing_time: Date.now()
        }
      };
    }
  }

  /**
   * Extract metadata using regex patterns
   */
  extractMetadata(type, html) {
    if (!html) return '';

    const patterns = this.extractionPatterns[type] || [];

    for (const pattern of patterns) {
      const match = html.match(pattern);
      if (match && match[1]) {
        return match[1].trim();
      }
    }

    return '';
  }

  /**
   * Count words in text
   */
  countWords(text) {
    if (!text) return 0;
    return text.split(/\s+/).filter(word => word.length > 0).length;
  }

  /**
   * Estimate reading time (average 200 words per minute)
   */
  estimateReadingTime(text) {
    const wordCount = this.countWords(text);
    return Math.max(1, Math.ceil(wordCount / 200));
  }

  /**
   * Determine content type based on content analysis
   */
  determineContentType(markdown, title) {
    const content = (markdown + ' ' + title).toLowerCase();

    // Check for research/academic content
    if (content.includes('research') || content.includes('study') || content.includes('survey')) {
      return 'research';
    }

    // Check for competitive intelligence
    if (content.includes('competitor') || content.includes('vs') || content.includes('comparison')) {
      return 'competitive_intel';
    }

    // Check for market analysis
    if (content.includes('market') || content.includes('industry') || content.includes('trend')) {
      return 'market_research';
    }

    // Check for documentation
    if (content.includes('api') || content.includes('documentation') || content.includes('guide')) {
      return 'documentation';
    }

    // Check for video content
    if (content.includes('video') || content.includes('watch') || content.includes('youtube')) {
      return 'video';
    }

    // Check for tool/product pages
    if (content.includes('features') || content.includes('pricing') || content.includes('product')) {
      return 'tool';
    }

    // Default to article
    return 'article';
  }

  /**
   * Analyze content for strategic indicators
   */
  analyzeStrategicContent(markdown) {
    if (!markdown) return { score: 0, indicators: [], categories: [] };

    const content = markdown.toLowerCase();
    const foundIndicators = [];
    const categories = [];

    // Check for strategic content indicators
    for (const [category, indicators] of Object.entries(this.strategicIndicators)) {
      const categoryMatches = indicators.filter(indicator =>
        content.includes(indicator.toLowerCase())
      );

      if (categoryMatches.length > 0) {
        foundIndicators.push(...categoryMatches);
        categories.push(category);
      }
    }

    // Calculate strategic score (0-10)
    let score = Math.min(10, foundIndicators.length * 2);

    // Boost score for high-value keywords
    const highValueKeywords = ['competitive', 'strategy', 'market analysis', 'ROI', 'revenue'];
    const highValueMatches = highValueKeywords.filter(keyword =>
      content.includes(keyword.toLowerCase())
    );
    score += highValueMatches.length * 2;

    return {
      score: Math.min(10, score),
      indicators: [...new Set(foundIndicators)],
      categories: [...new Set(categories)]
    };
  }

  /**
   * Batch process multiple URLs
   */
  async batchExtractContent(urls, options = {}) {
    console.log(`[Firecrawl] Starting batch extraction for ${urls.length} URLs`);

    const results = [];
    const concurrency = options.concurrency || 3;

    // Process URLs in batches to avoid overwhelming the service
    for (let i = 0; i < urls.length; i += concurrency) {
      const batch = urls.slice(i, i + concurrency);
      const batchPromises = batch.map(url => this.extractContent(url, options));

      try {
        const batchResults = await Promise.all(batchPromises);
        results.push(...batchResults);
      } catch (error) {
        console.error(`[Firecrawl] Batch processing error:`, error);
      }

      // Add delay between batches
      if (i + concurrency < urls.length) {
        await new Promise(resolve => setTimeout(resolve, 1000));
      }
    }

    console.log(`[Firecrawl] Batch extraction completed: ${results.length} results`);
    return results;
  }

  /**
   * Search for related content
   */
  async searchRelatedContent(query, domain = null) {
    try {
      const searchParams = {
        query: query,
        limit: 20
      };

      if (domain) {
        searchParams.domain = domain;
      }

      const searchResult = await this.executeMCPCommand(this.tools.search, searchParams);

      if (!searchResult.success) {
        throw new Error(`Search failed: ${searchResult.error}`);
      }

      return searchResult.data.results || [];

    } catch (error) {
      console.error(`[Firecrawl] Search failed for query "${query}":`, error);
      return [];
    }
  }

  /**
   * Extract competitive intelligence from content
   */
  extractCompetitiveIntelligence(extractedContent) {
    const { markdown, metadata } = extractedContent.raw_content;
    const content = (markdown + ' ' + metadata?.title + ' ' + metadata?.description).toLowerCase();

    const competitiveIntel = {
      competitors_mentioned: [],
      strategic_insights: [],
      market_data: [],
      threats: [],
      opportunities: []
    };

    // Extract competitor mentions
    const competitorPatterns = [
      /competitor[s]?[:\s]+([^.!?]+)/gi,
      /vs\.?\s+([^.!?]+)/gi,
      /compared\s+to\s+([^.!?]+)/gi
    ];

    competitorPatterns.forEach(pattern => {
      let match;
      while ((match = pattern.exec(content)) !== null) {
        competitiveIntel.competitors_mentioned.push(match[1].trim());
      }
    });

    // Extract market data
    const marketDataPatterns = [
      /market\s+size[:\s]+([^.!?]+)/gi,
      /revenue[:\s]+\$?([0-9.,]+[bmk]?)/gi,
      /growth[:\s]+([0-9.,]+%)/gi
    ];

    marketDataPatterns.forEach(pattern => {
      let match;
      while ((match = pattern.exec(content)) !== null) {
        competitiveIntel.market_data.push(match[1].trim());
      }
    });

    return competitiveIntel;
  }

  /**
   * Save extraction results to file
   */
  async saveExtractionResults(url, extractedContent) {
    try {
      const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
      const domain = new URL(url).hostname.replace(/\./g, '_');
      const filename = `extraction_${domain}_${timestamp}.json`;
      const filepath = path.join(this.tempPath, filename);

      await fs.writeFile(filepath, JSON.stringify(extractedContent, null, 2));
      console.log(`[Firecrawl] Extraction results saved to: ${filename}`);

      return filepath;
    } catch (error) {
      console.error(`[Firecrawl] Failed to save extraction results:`, error);
    }
  }
}

module.exports = FirecrawlIntegration;

// CLI interface for testing
if (require.main === module) {
  const firecrawl = new FirecrawlIntegration();

  async function runTest() {
    try {
      await firecrawl.initialize();

      const testUrl = 'https://example.com/strategic-analysis';
      console.log(`Testing content extraction for: ${testUrl}`);

      const result = await firecrawl.extractContent(testUrl, { includeRelatedLinks: true });
      console.log('Extraction result:', JSON.stringify(result, null, 2));

      await firecrawl.saveExtractionResults(testUrl, result);

    } catch (error) {
      console.error('Test failed:', error);
    }
  }

  runTest();
}

