  /**
   * Run tests for a specific category
   */
  async runTestCategory(category, title) {
    console.log(`${title}`);
    console.log('='.repeat(title.length));

    const tests = this.testCases[category];

    for (const testCase of tests) {
      await this.runSingleTest(testCase);
    }

    console.log('');
  }

  /**
   * Run a single test case
   */
  async runSingleTest(testCase) {
    const startTime = Date.now();
    this.testResults.total++;

    try {
      console.log(`  ⏳ ${testCase.name}...`);

      const result = await testCase.test();
      const duration = Date.now() - startTime;

      if (result.success) {
        console.log(`  ✅ ${testCase.name} (${duration}ms)`);
        this.testResults.passed++;
      } else {
        console.log(`  ❌ ${testCase.name} - ${result.error} (${duration}ms)`);
        this.testResults.failed++;
      }

      this.testResults.details.push({
        name: testCase.name,
        category: testCase.category,
        success: result.success,
        duration,
        error: result.error || null,
        details: result.details || null
      });

    } catch (error) {
      const duration = Date.now() - startTime;
      console.log(`  ❌ ${testCase.name} - Exception: ${error.message} (${duration}ms)`);

      this.testResults.failed++;
      this.testResults.details.push({
        name: testCase.name,
        category: testCase.category,
        success: false,
        duration,
        error: error.message
      });
    }
  }

