      const immediateTime = Date.now() - startTime;

      if (immediateTime > benchmarks.immediate_assessment) {
        throw new Error(`Immediate assessment too slow: ${immediateTime}ms > ${benchmarks.immediate_assessment}ms`);
      }

      return {
        success: true,
        details: `Performance benchmarks met: immediate assessment ${immediateTime}ms`
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testErrorHandling() {
    try {
      const db = new LinkDatabase(this.basePath);
      await db.initialize();

      // Test invalid URL handling
      try {
        await db.addLink({ url: 'invalid-url' });
        throw new Error('Invalid URL should have been rejected');
      } catch (error) {
        if (!error.message.includes('Invalid URL format')) {
          throw error;
        }
      }

      // Test duplicate handling
      const validUrl = 'https://error-test.com/page';
      await db.addLink({ url: validUrl, title: 'First Link' });

      try {
        await db.addLink({ url: validUrl, title: 'Duplicate Link' });
        throw new Error('Duplicate should have been rejected');
      } catch (error) {
        if (!error.message.includes('Duplicate link detected')) {
          throw error;
        }
      }

      return { success: true, details: 'Error handling working correctly' };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testDataPersistence() {
    try {
      const db = new LinkDatabase(this.basePath);
      await db.initialize();

      // Add test data
      const testLink = {
        url: 'https://persistence-test.com',
        title: 'Persistence Test',
        business_impact: 7
      };

      const savedLink = await db.addLink(testLink);

      // Create new database instance to test persistence
      const db2 = new LinkDatabase(this.basePath);
      await db2.initialize();

      const links = await db2.loadCollection('links');
      const persistedLink = links.find(l => l.id === savedLink.id);

      if (!persistedLink) {
        throw new Error('Data not persisted across database instances');
      }

      return { success: true, details: 'Data persistence working correctly' };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  /**
   * Generate comprehensive test report
   */
  async generateTestReport() {
    const report = {
      summary: {
        total_tests: this.testResults.total,
        passed: this.testResults.passed,
        failed: this.testResults.failed,
        success_rate: (this.testResults.passed / this.testResults.total * 100).toFixed(2) + '%',
        total_duration: this.testResults.duration + 'ms',
        timestamp: new Date().toISOString()
      },
      categories: {
        database: this.getCategoryStats('core'),
        firecrawl: this.getCategoryStats('integration'),
        summarization: this.getCategoryStats('summarization'),
        integration: this.getCategoryStats('e2e')
      },
      detailed_results: this.testResults.details,
      performance_metrics: this.extractPerformanceMetrics(),
      recommendations: this.generateRecommendations()
    };

    const reportPath = path.join(this.testResultsPath, `test-report-${Date.now()}.json`);
    await fs.writeFile(reportPath, JSON.stringify(report, null, 2));

    console.log(`📊 Detailed test report saved to: ${reportPath}`);
    return report;
  }

  /**
   * Get statistics for a test category
   */
  getCategoryStats(category) {
    const categoryTests = this.testResults.details.filter(t => t.category === category);
    const passed = categoryTests.filter(t => t.success).length;

    return {
      total: categoryTests.length,
      passed,
      failed: categoryTests.length - passed,
      success_rate: categoryTests.length > 0 ? (passed / categoryTests.length * 100).toFixed(2) + '%' : '0%'
    };
  }

  /**
   * Extract performance metrics from test results
   */
  extractPerformanceMetrics() {
    const performanceTests = this.testResults.details.filter(t =>
      t.name.includes('Performance') || t.category === 'performance'
    );

    return {
      average_test_duration: this.testResults.details.reduce((sum, t) => sum + t.duration, 0) / this.testResults.details.length,
      slowest_test: this.testResults.details.reduce((max, t) => t.duration > max.duration ? t : max),
      fastest_test: this.testResults.details.reduce((min, t) => t.duration < min.duration ? t : min)
    };
  }

  /**
   * Generate recommendations based on test results
   */
  generateRecommendations() {
    const recommendations = [];

    if (this.testResults.failed > 0) {
      recommendations.push('Address failing tests before production deployment');
    }

    const successRate = this.testResults.passed / this.testResults.total;
    if (successRate < 0.95) {
      recommendations.push('Improve test coverage and reliability - aim for >95% success rate');
    }

    const avgDuration = this.testResults.details.reduce((sum, t) => sum + t.duration, 0) / this.testResults.details.length;
    if (avgDuration > 5000) {
      recommendations.push('Optimize test performance - average test duration is high');
    }

    if (recommendations.length === 0) {
      recommendations.push('All tests passing - system ready for production deployment');
    }

    return recommendations;
  }

  /**
   * Print test summary
   */
  printTestSummary() {
    console.log('\n📋 TEST SUMMARY');
    console.log('================');
    console.log(`Total Tests: ${this.testResults.total}`);
    console.log(`Passed: ${this.testResults.passed} ✅`);
    console.log(`Failed: ${this.testResults.failed} ❌`);
    console.log(`Success Rate: ${(this.testResults.passed / this.testResults.total * 100).toFixed(1)}%`);
    console.log(`Duration: ${(this.testResults.duration / 1000).toFixed(2)}s`);

    if (this.testResults.failed > 0) {
      console.log('\n❌ Failed Tests:');
      this.testResults.details.filter(t => !t.success).forEach(test => {
        console.log(`  - ${test.name}: ${test.error}`);
      });
    }

    console.log('\n🏆 Link Logger Agent Test Suite Complete!');

    if (this.testResults.failed === 0) {
      console.log('✨ All tests passed - system ready for production!');
    } else {
      console.log('⚠️  Some tests failed - review and fix before deployment');
    }
  }
}

// CLI interface
if (require.main === module) {
  const testSuite = new LinkLoggerTestSuite();

  async function runTests() {
    try {
      await testSuite.initialize();
      const results = await testSuite.runAllTests();

      process.exit(results.failed > 0 ? 1 : 0);
    } catch (error) {
      console.error('Test suite failed:', error);
      process.exit(1);
    }
  }

  runTests();
}

module.exports = LinkLoggerTestSuite;

