#!/usr/bin/env node
/**
 * Comprehensive Test Suite for Link Logger Agent
 * Production Strategic Intelligence Testing
 *
 * @author link-logger-agent
 * @version 1.0.0
 * @created 2025-10-31
 */

const LinkDatabase = require('./link-database.js');
const FirecrawlIntegration = require('./firecrawl-integration.js');
const SummarizationPipeline = require('./summarization-pipeline.js');
const fs = require('fs').promises;
const path = require('path');

class LinkLoggerTestSuite {
  constructor() {
    this.basePath = '/workspaces/agent-feed/prod/agent_workspace/link-logger-agent';
    this.testResultsPath = path.join(this.basePath, 'test-results');

    this.testCases = {
      database: [],
      firecrawl: [],
      summarization: [],
      integration: []
    };

    this.testResults = {
      total: 0,
      passed: 0,
      failed: 0,
      duration: 0,
      details: []
    };
  }

  /**
   * Initialize test suite
   */
  async initialize() {
    console.log('\n🔗 Link Logger Agent Test Suite');
    console.log('=====================================');
    console.log('Production Strategic Intelligence Testing\n');

    // Create test results directory
    await fs.mkdir(this.testResultsPath, { recursive: true });

    // Load test configurations
    this.loadTestCases();

    return true;
  }

  /**
   * Load all test cases
   */
  loadTestCases() {
    // Database Tests
    this.testCases.database = [
      {
        name: 'Database Initialization',
        test: () => this.testDatabaseInitialization(),
        category: 'core'
      },
      {
        name: 'URL Validation and Normalization',
        test: () => this.testUrlValidation(),
        category: 'validation'
      },
      {
        name: 'Link Storage and Retrieval',
        test: () => this.testLinkStorage(),
        category: 'storage'
      },
      {
        name: 'Duplicate Detection',
        test: () => this.testDuplicateDetection(),
        category: 'validation'
      },
      {
        name: 'Strategic Value Calculation',
        test: () => this.testStrategicValueCalculation(),
        category: 'analysis'
      },
      {
        name: 'Search Functionality',
        test: () => this.testSearchFunctionality(),
        category: 'retrieval'
      }
    ];

    // Firecrawl Integration Tests
    this.testCases.firecrawl = [
      {
        name: 'Firecrawl Integration Setup',
        test: () => this.testFirecrawlSetup(),
        category: 'integration'
      },
      {
        name: 'Content Extraction',
        test: () => this.testContentExtraction(),
        category: 'extraction'
      },
      {
        name: 'Metadata Extraction',
        test: () => this.testMetadataExtraction(),
        category: 'extraction'
      },
      {
        name: 'Strategic Content Analysis',
        test: () => this.testStrategicContentAnalysis(),
        category: 'analysis'
      },
      {
        name: 'Batch Processing',
        test: () => this.testBatchProcessing(),
        category: 'performance'
      }
    ];

    // Summarization Pipeline Tests
    this.testCases.summarization = [
      {
        name: 'Pipeline Initialization',
        test: () => this.testSummarizationSetup(),
        category: 'core'
      },
      {
        name: 'Immediate Strategic Assessment',
        test: () => this.testImmediateAssessment(),
        category: 'summarization'
      },
      {
        name: 'Tactical Intelligence Brief',
        test: () => this.testTacticalBrief(),
        category: 'summarization'
      },
      {
        name: 'Strategic Analysis',
        test: () => this.testStrategicAnalysis(),
        category: 'summarization'
      },
      {
        name: 'Competitive Intelligence',
        test: () => this.testCompetitiveIntelligence(),
        category: 'intelligence'
      },
      {
        name: 'Progressive Summarization',
        test: () => this.testProgressiveSummarization(),
        category: 'summarization'
      }
    ];

    // Integration Tests
    this.testCases.integration = [
      {
        name: 'End-to-End Link Processing',
        test: () => this.testEndToEndProcessing(),
        category: 'e2e'
      },
      {
        name: 'Strategic Intelligence Workflow',
        test: () => this.testStrategicWorkflow(),
        category: 'workflow'
      },
      {
        name: 'Performance Benchmarks',
        test: () => this.testPerformanceBenchmarks(),
        category: 'performance'
      },
      {
        name: 'Error Handling',
        test: () => this.testErrorHandling(),
        category: 'reliability'
      },
      {
        name: 'Data Persistence',
        test: () => this.testDataPersistence(),
        category: 'storage'
      }
    ];
  }

  /**
   * Run complete test suite
   */
  async runAllTests() {
    const startTime = Date.now();

    console.log('Starting comprehensive test execution...\n');

    // Run all test categories
    await this.runTestCategory('database', '📊 Database Tests');
    await this.runTestCategory('firecrawl', '🔍 Firecrawl Integration Tests');
    await this.runTestCategory('summarization', '📝 Summarization Pipeline Tests');
    await this.runTestCategory('integration', '🔗 Integration Tests');

    // Calculate results
    this.testResults.duration = Date.now() - startTime;

    // Generate report
    await this.generateTestReport();

    // Print summary
    this.printTestSummary();

    return this.testResults;
  }

  /**
   * Run tests for a specific category
   */
  async runTestCategory(category, title) {
    console.log(`${title}`);
    console.log('='.repeat(title.length));

    const tests = this.testCases[category];

    for (const testCase of tests) {
      await this.runSingleTest(testCase);
    }

    console.log('');
  }

  /**
   * Run a single test case
   */
  async runSingleTest(testCase) {
    const startTime = Date.now();
    this.testResults.total++;

    try {
      console.log(`  ⏳ ${testCase.name}...`);

      const result = await testCase.test();
      const duration = Date.now() - startTime;

      if (result.success) {
        console.log(`  ✅ ${testCase.name} (${duration}ms)`);
        this.testResults.passed++;
      } else {
        console.log(`  ❌ ${testCase.name} - ${result.error} (${duration}ms)`);
        this.testResults.failed++;
      }

      this.testResults.details.push({
        name: testCase.name,
        category: testCase.category,
        success: result.success,
        duration,
        error: result.error || null,
        details: result.details || null
      });

    } catch (error) {
      const duration = Date.now() - startTime;
      console.log(`  ❌ ${testCase.name} - Exception: ${error.message} (${duration}ms)`);

      this.testResults.failed++;
      this.testResults.details.push({
        name: testCase.name,
        category: testCase.category,
        success: false,
        duration,
        error: error.message
      });
    }
  }

  // ======================
  // DATABASE TESTS
  // ======================

  async testDatabaseInitialization() {
    try {
      const db = new LinkDatabase(this.basePath);
      await db.initialize();

      // Check if required files exist
      const requiredFiles = [
        'database-schema.json',
        'database/links.json',
        'database/knowledge-index.json',
        'database/search-index.json',
        'database/processing-queue.json',
        'database/strategic-briefs.json'
      ];

      for (const file of requiredFiles) {
        const filePath = path.join(this.basePath, file);
        await fs.access(filePath);
      }

      return { success: true, details: 'Database initialized with all required files' };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testUrlValidation() {
    try {
      const db = new LinkDatabase(this.basePath);
      await db.initialize();

      const testUrls = [
        { url: 'https://example.com/valid', shouldPass: true },
        { url: 'http://test.com/page', shouldPass: true },
        { url: 'invalid-url', shouldPass: false },
        { url: 'ftp://example.com', shouldPass: false },
        { url: 'https://example.com' + 'x'.repeat(3000), shouldPass: false }
      ];

      let passed = 0;
      for (const test of testUrls) {
        try {
          db.validateUrl(test.url);
          if (test.shouldPass) passed++;
        } catch (error) {
          if (!test.shouldPass) passed++;
        }
      }

      const success = passed === testUrls.length;
      return {
        success,
        details: `${passed}/${testUrls.length} validation tests passed`,
        error: success ? null : 'URL validation failed'
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testLinkStorage() {
    try {
      const db = new LinkDatabase(this.basePath);
      await db.initialize();

      const testLink = {
        url: 'https://test-strategic-content.com/analysis',
        title: 'Test Strategic Analysis',
        description: 'Test content for strategic analysis',
        business_impact: 8,
        competitive_relevance: 7,
        market_intelligence_value: 9,
        time_sensitivity: 6,
        strategic_priority: 'high',
        primary_category: 'competitive_intelligence',
        tags: ['test', 'strategic', 'analysis']
      };

      const savedLink = await db.addLink(testLink);

      if (!savedLink.id || savedLink.url !== testLink.url) {
        throw new Error('Link not properly saved');
      }

      // Test retrieval
      const links = await db.loadCollection('links');
      const retrievedLink = links.find(l => l.id === savedLink.id);

      if (!retrievedLink) {
        throw new Error('Link not retrievable after storage');
      }

      return {
        success: true,
        details: `Link stored with ID: ${savedLink.id}, strategic value: ${savedLink.analysis.strategic_value}`
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testDuplicateDetection() {
    try {
      const db = new LinkDatabase(this.basePath);
      await db.initialize();

      const originalUrl = 'https://duplicate-test.com/page';

      // Add first link
      await db.addLink({
        url: originalUrl,
        title: 'Original Link',
        business_impact: 5
      });

      // Test exact duplicate detection
      try {
        await db.addLink({
          url: originalUrl,
          title: 'Duplicate Link'
        });
        throw new Error('Duplicate detection failed - exact match not caught');
      } catch (error) {
        if (!error.message.includes('Duplicate link detected')) {
          throw error;
        }
      }

      // Test fuzzy duplicate detection
      const duplicateCheck = await db.checkDuplicate(originalUrl + '?utm_source=test');
      if (!duplicateCheck.isDuplicate) {
        throw new Error('Fuzzy duplicate detection failed');
      }

      return {
        success: true,
        details: 'Exact and fuzzy duplicate detection working'
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testStrategicValueCalculation() {
    try {
      const db = new LinkDatabase(this.basePath);
      await db.initialize();

      const testAnalysis = {
        business_impact: 9,
        competitive_relevance: 8,
        market_intelligence_value: 7,
        time_sensitivity: 6
      };

      const strategicValue = db.calculateStrategicValue(testAnalysis);

      // Expected: (9*0.3) + (8*0.25) + (7*0.25) + (6*0.2) = 2.7 + 2 + 1.75 + 1.2 = 7.65 ≈ 7.7
      const expected = 7.7;
      const tolerance = 0.1;

      if (Math.abs(strategicValue - expected) > tolerance) {
        throw new Error(`Strategic value calculation incorrect: got ${strategicValue}, expected ~${expected}`);
      }

      return {
        success: true,
        details: `Strategic value calculated correctly: ${strategicValue}`
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testSearchFunctionality() {
    try {
      const db = new LinkDatabase(this.basePath);
      await db.initialize();

      // Add test links
      const testLinks = [
        {
          url: 'https://search-test-1.com',
          title: 'Strategic AI Analysis',
          tags: ['AI', 'strategy', 'analysis'],
          business_impact: 8
        },
        {
          url: 'https://search-test-2.com',
          title: 'Market Research Report',
          tags: ['market', 'research'],
          business_impact: 6
        },
        {
          url: 'https://search-test-3.com',
          title: 'AI Competition Study',
          tags: ['AI', 'competition'],
          business_impact: 9
        }
      ];

      for (const link of testLinks) {
        await db.addLink(link);
      }

      // Test text search
      const aiResults = await db.search('AI');
      if (aiResults.length !== 2) {
        throw new Error(`Text search failed: expected 2 AI results, got ${aiResults.length}`);
      }

      // Test filter by strategic value
      const highValueResults = await db.search('', { strategic_value_min: 8 });
      if (highValueResults.length < 1) {
        throw new Error('Strategic value filtering failed');
      }

      // Test tag filtering
      const tagResults = await db.search('', { tags: 'strategy' });
      if (tagResults.length < 1) {
        throw new Error('Tag filtering failed');
      }

      return {
        success: true,
        details: `Search tests passed: ${aiResults.length} text results, ${highValueResults.length} high-value results`
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  // ======================
  // FIRECRAWL TESTS
  // ======================

  async testFirecrawlSetup() {
    try {
      const firecrawl = new FirecrawlIntegration(this.basePath);
      await firecrawl.initialize();

      // Check temp directory creation
      const tempPath = path.join(this.basePath, 'temp');
      await fs.access(tempPath);

      return { success: true, details: 'Firecrawl integration initialized' };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testContentExtraction() {
    try {
      const firecrawl = new FirecrawlIntegration(this.basePath);
      await firecrawl.initialize();

      const testUrl = 'https://example.com/strategic-content';
      const result = await firecrawl.extractContent(testUrl);

      if (!result.extraction_metadata.success) {
        throw new Error('Content extraction failed');
      }

      if (!result.raw_content || !result.metadata) {
        throw new Error('Extracted content missing required fields');
      }

      return {
        success: true,
        details: `Content extracted successfully: ${result.content_analysis?.word_count || 0} words`
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testMetadataExtraction() {
    try {
      const firecrawl = new FirecrawlIntegration(this.basePath);

      const testHtml = `
        <html>
          <head>
            <title>Test Strategic Content</title>
            <meta name="description" content="Strategic analysis content">
            <meta name="author" content="Test Author">
          </head>
          <body>Content</body>
        </html>
      `;

      const title = firecrawl.extractMetadata('title', testHtml);
      const description = firecrawl.extractMetadata('description', testHtml);
      const author = firecrawl.extractMetadata('author', testHtml);

      if (title !== 'Test Strategic Content' || !description || !author) {
        throw new Error('Metadata extraction failed');
      }

      return {
        success: true,
        details: `Metadata extracted: title, description, author`
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testStrategicContentAnalysis() {
    try {
      const firecrawl = new FirecrawlIntegration(this.basePath);

      const testContent = `
        This market analysis reveals significant competitive threats from AI automation.
        Revenue growth of 45% indicates strong market expansion opportunities.
        Strategic partnerships with technology leaders will be essential for success.
        Investment in artificial intelligence capabilities should be prioritized.
      `;

      const analysis = firecrawl.analyzeStrategicContent(testContent);

      if (analysis.score < 5) {
        throw new Error(`Strategic content score too low: ${analysis.score}`);
      }

      if (analysis.indicators.length === 0) {
        throw new Error('No strategic indicators detected');
      }

      return {
        success: true,
        details: `Strategic analysis: score ${analysis.score}, ${analysis.indicators.length} indicators`
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testBatchProcessing() {
    try {
      const firecrawl = new FirecrawlIntegration(this.basePath);
      await firecrawl.initialize();

      const testUrls = [
        'https://example.com/page1',
        'https://example.com/page2',
        'https://example.com/page3'
      ];

      const results = await firecrawl.batchExtractContent(testUrls, { concurrency: 2 });

      if (results.length !== testUrls.length) {
        throw new Error(`Batch processing failed: expected ${testUrls.length} results, got ${results.length}`);
      }

      return {
        success: true,
        details: `Batch processed ${results.length} URLs successfully`
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  // ======================
  // SUMMARIZATION TESTS
  // ======================

  async testSummarizationSetup() {
    try {
      const pipeline = new SummarizationPipeline(this.basePath);
      await pipeline.initialize();

      // Check templates directory creation
      const templatesPath = path.join(this.basePath, 'templates');
      await fs.access(templatesPath);

      return { success: true, details: 'Summarization pipeline initialized' };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testImmediateAssessment() {
    try {
      const pipeline = new SummarizationPipeline(this.basePath);
      await pipeline.initialize();

      const testContent = {
        raw_content: {
          markdown: 'Strategic AI market analysis reveals 45% growth and significant competitive threats.'
        },
        metadata: {
          title: 'Strategic Analysis',
          domain: 'strategicinsights.com'
        }
      };

      const result = await pipeline.immediateAssessment(testContent);

      if (!result.executive_brief || !result.strategic_score) {
        throw new Error('Immediate assessment missing required fields');
      }

      if (result.duration > 30000) { // 30 seconds
        throw new Error(`Assessment took too long: ${result.duration}ms`);
      }

      return {
        success: true,
        details: `Assessment completed in ${result.duration}ms, strategic score: ${result.strategic_score}`
      };
    } catch (error) {
      return { success: false, error: error.message };
    }
  }

  async testTacticalBrief() {
    try {
      const pipeline = new SummarizationPipeline(this.basePath);
      await pipeline.initialize();

      const testContent = {
        raw_content: {
          markdown: `Strategic market analysis shows 45% revenue growth.
