   * Get statistics for a test category
   */
  getCategoryStats(category) {
    const categoryTests = this.testResults.details.filter(t => t.category === category);
    const passed = categoryTests.filter(t => t.success).length;

    return {
      total: categoryTests.length,
      passed,
      failed: categoryTests.length - passed,
      success_rate: categoryTests.length > 0 ? (passed / categoryTests.length * 100).toFixed(2) + '%' : '0%'
    };
  }

  /**
   * Extract performance metrics from test results
   */
  extractPerformanceMetrics() {
    const performanceTests = this.testResults.details.filter(t =>
      t.name.includes('Performance') || t.category === 'performance'
    );

    return {
      average_test_duration: this.testResults.details.reduce((sum, t) => sum + t.duration, 0) / this.testResults.details.length,
      slowest_test: this.testResults.details.reduce((max, t) => t.duration > max.duration ? t : max),
      fastest_test: this.testResults.details.reduce((min, t) => t.duration < min.duration ? t : min)
    };
  }

  /**
   * Generate recommendations based on test results
   */
  generateRecommendations() {
    const recommendations = [];

    if (this.testResults.failed > 0) {
      recommendations.push('Address failing tests before production deployment');
    }

    const successRate = this.testResults.passed / this.testResults.total;
    if (successRate < 0.95) {
      recommendations.push('Improve test coverage and reliability - aim for >95% success rate');
    }

    const avgDuration = this.testResults.details.reduce((sum, t) => sum + t.duration, 0) / this.testResults.details.length;
    if (avgDuration > 5000) {
      recommendations.push('Optimize test performance - average test duration is high');
    }

    if (recommendations.length === 0) {
      recommendations.push('All tests passing - system ready for production deployment');
    }

    return recommendations;
  }

  /**
   * Print test summary
   */
  printTestSummary() {
    console.log('\n📋 TEST SUMMARY');
    console.log('================');
    console.log(`Total Tests: ${this.testResults.total}`);
    console.log(`Passed: ${this.testResults.passed} ✅`);
    console.log(`Failed: ${this.testResults.failed} ❌`);
    console.log(`Success Rate: ${(this.testResults.passed / this.testResults.total * 100).toFixed(1)}%`);
    console.log(`Duration: ${(this.testResults.duration / 1000).toFixed(2)}s`);

    if (this.testResults.failed > 0) {
      console.log('\n❌ Failed Tests:');
      this.testResults.details.filter(t => !t.success).forEach(test => {
        console.log(`  - ${test.name}: ${test.error}`);
      });
    }

    console.log('\n🏆 Link Logger Agent Test Suite Complete!');

    if (this.testResults.failed === 0) {
      console.log('✨ All tests passed - system ready for production!');
    } else {
      console.log('⚠️  Some tests failed - review and fix before deployment');
    }
  }
}

// CLI interface
if (require.main === module) {
  const testSuite = new LinkLoggerTestSuite();

  async function runTests() {
    try {
      await testSuite.initialize();
      const results = await testSuite.runAllTests();

      process.exit(results.failed > 0 ? 1 : 0);
    } catch (error) {
      console.error('Test suite failed:', error);
      process.exit(1);
    }
  }

  runTests();
}

module.exports = LinkLoggerTestSuite;

