    total_results: results.length,
    average_strategic_value: 0,
    categories: {},
    high_priority_alerts: [],
    recommended_actions: []
  };

  if (results.length > 0) {
    // Calculate metrics
    analysis.average_strategic_value = results.reduce((sum, link) =>
      sum + link.analysis.strategic_value, 0) / results.length;

    // Categorize results
    results.forEach(link => {
      const category = link.categorization.primary_category;
      analysis.categories[category] = (analysis.categories[category] || 0) + 1;

      // Identify high-priority items
      if (link.analysis.strategic_value >= 9) {
        analysis.high_priority_alerts.push({
          title: link.metadata.title,
          url: link.url,
          strategic_value: link.analysis.strategic_value,
          category: category,
          captured_date: link.captured_date
