### Health Checks

```javascript
// System health check
async function healthCheck() {
  const db = new LinkDatabase();
  const firecrawl = new FirecrawlIntegration();
  const pipeline = new SummarizationPipeline();

  const health = {
    database: false,
    firecrawl: false,
    pipeline: false,
    timestamp: new Date().toISOString()
  };

  try {
    await db.initialize();
    health.database = true;
  } catch (error) {
    console.error('Database health check failed:', error);
  }

  try {
    await firecrawl.initialize();
    health.firecrawl = true;
  } catch (error) {
    console.error('Firecrawl health check failed:', error);
  }

  try {
    await pipeline.initialize();
    health.pipeline = true;
  } catch (error) {
    console.error('Pipeline health check failed:', error);
  }

  const overallHealth = health.database && health.firecrawl && health.pipeline;
  console.log(`🏥 System Health: ${overallHealth ? '✅ Healthy' : '❌ Issues Detected'}`);

  return health;
}
```

